import React, { useState } from 'react';
import './Dashboard.css';

const Dashboard = () => {
  const [comment, setComment] = useState('');
  const [allComments, setAllComments] = useState([]);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const handleSendCommnet = () => {
    if (comment.trim() !== '') {
      setAllComments({...allComments, comment});
      setComment('');
    }
  }
  const toggleChat = () => {
    setIsChatOpen(!isChatOpen);
  };

  return (
    <>
      <div className={`chat-fixed-container ${isChatOpen ? 'open' : ''}`}>
        <div className="chat-fixed-header" onClick={toggleChat}> 
          <h3>Chat</h3>
          <div className="chat-header-actions">
            <button onClick={toggleChat} className="chat-close-btn">X</button> 
          </div>
        </div>

        <div className="chat-fixed-body">
          <div className="chat-messages-placeholder">
            {allComments.map((msg, index) => (
              <div key={index} className="chat-message">
                {msg}
              </div>
            ))}
          </div>
          
          <div className="chat-fixed-input-area">
            <textarea placeholder="Deixe seu comentário aqui..." value={comment} onChange={(e) => setComment(e.target.value)} />
            <button className="send-button-fixed" onClick={handleSendCommnet}>Enviar</button>
          </div>
        </div>
      </div>

      <div className="dashboard-container">
        <aside className="sidebar">
          <h2>AgroMonitor</h2>
          <nav>
            <ul>
              <li className="active">Visão Geral</li>
              <li>Estufas</li>
              <li>Relatórios</li>
              <li>Cadastro</li>
              <li>Configurações</li>
            </ul>
          </nav>
        </aside>

        <main className="main-content">
          <header className="dashboard-header">
            <h1>Painel de Controle</h1>
          </header>

          <section className="stats-grid">
            <div className="stat-card">
              <h3>Temperatura</h3>
              <p>24°C</p>
              <span>Status: Ideal</span>
            </div>
            <div className="stat-card">
              <h3>Umidade Solo</h3>
              <p>65%</p>
              <span>Status: Estável</span>
            </div>
            <div className="stat-card">
              <h3>Luminosidade</h3>
              <p>80%</p>
              <span>Status: Alto</span>
            </div>
          </section>
        </main>
      </div>
    </>
  );
};

export default Dashboard;
